                                      '        "booking_order_amount": '
                                      'base._float(source.get("booking_order_amount")),\n'
                                      '        "business_date": next(\n'
                                      '            (\n'
                                      '                str(source.get(name) or "")[:10]\n'
                                      '                for name in _DATE_COLUMNS\n'
                                      '                if source.get(name) not in (None, "")\n'
