                                      'from "\n'
                                      '            "meituan_ota_promotion_performance_30d; spend_amount and "\n'
                                      '            "booking_order_amount map directly"\n'
                                      '        ),\n'
                                      '    }\n'
                                      '\n'
                                      '\n'
                                      'def load_mysql_dsn_dataset(\n'
                                      '    dsn: str,\n'
                                      '    limit: int = 5000,\n'
                                      '    tables: dict[str, str] | None = None,\n'
                                      '    hotel_id: str | None = "puyue",\n'
                                      '    platform: str | None = "multi",\n'
