                                      '        return dataset\n'
                                      '\n'
                                      '    table = table_map["meituan_promotion_performance_30d"]\n'
                                      '    with base._connect_mysql(dsn) as conn:\n'
                                      '        with conn.cursor() as cursor:\n'
                                      '            summary, diag = _load_latest_promotion_performance(\n'
                                      '                cursor,\n'
