                                     '    except Exception as exc:\n'
                                     '        return None, {\n'
                                     '            "table": table,\n'
                                     '            "where": where,\n'
                                     '            "rows": 0,\n'
                                     '            "aggregation": "COUNT(*)",\n'
                                     '            "date_column": date_column,\n'
                                     '            "table_columns": sorted(columns),\n'
                                     '            "status": "error",\n'
                                     '            "error": str(exc),\n'
                                     '        }\n'
                                     '\n'
                                     '\n'
                                     'def _diagnostics(dataset: dict[str, Any]) -> dict[str, Any] | None:\n'
                                     '    records = dataset.get("__source_diagnostics__") or []\n'
                                     '    return records[0] if records and isinstance(records[0], dict) else None\n'
                                     '\n'
                                     '\n'
                                     'def load_mysql_dsn_dataset(\n'
                                     '    dsn: str,\n'
                                     '    limit: int = 5000,\n'
                                     '    tables: dict[str, str] | None = None,\n'
                                     '    hotel_id: str | None = "puyue",\n'
                                     '    platform: str | None = "multi",\n'
                                     '    period_start: str | None = None,\n'
                                     '    period_end: str | None = None,\n'
                                     ') -> dict[str, list[dict[str, Any]]]:\n'
                                     '    table_map = {**DEFAULT_MYSQL_TABLES, **(tables or {})}\n'
                                     '    dataset = base.load_mysql_dsn_dataset(\n'
                                     '        dsn,\n'
