                                     '    review_table = table_map["meituan_review_overview"]\n'
                                     '    meituan_enabled = "meituan" in previous.base._enabled_platforms(platform)\n'
                                     '\n'
                                     '    review_rows: list[dict[str, Any]] = []\n'
                                     '    review_diag: dict[str, Any] = {}\n'
                                     '\n'
