                                     '        room_table,\n'
                                     '    )\n'
                                     '\n'
                                     '    diagnostics = _diagnostics(dataset)\n'
                                     '    if diagnostics is not None:\n'
                                     '        diagnostics.setdefault("tables", {})["jl01"] = {\n'
                                     '            **room_diag,\n'
                                     '            "rows_used": len(daily_room_rows),\n'
                                     '            "aggregation_rule": (\n'
                                     '                "按 business_date + 房型去重，每组保留最新 snapshot_time；"\n'
                                     '                "直接读取 occupancy_rate、revpar、room_nights、room_revenue"\n'
                                     '            ),\n'
                                     '        }\n'
                                     '        diagnostics.setdefault("transformations", []).append(\n'
                                     '            {\n'
                                     '                "section": "room_type_performance_daily",\n'
                                     '                "rows": len(daily_room_rows),\n'
                                     '                "rule": (\n'
                                     '                    "wide jl01 daily rows filtered by requested business_date '
                                     'range "\n'
                                     '                    "and deduplicated by day + room"\n'
                                     '                ),\n'
                                     '            }\n'
                                     '        )\n'
                                     '\n'
                                     '    if not meituan_enabled:\n'
                                     '        return dataset\n'
                                     '\n'
                                     '    latest_reviews = _latest_review_overview_per_platform(review_rows)\n'
                                     '    preserved = [\n'
                                     '        row\n'
                                     '        for row in dataset.get("review_overviews") or []\n'
                                     '        if str(row.get("source_table") or row.get("__source_table") or "") != '
                                     'review_table\n'
                                     '    ]\n'
                                     '    dataset["review_overviews"] = preserved + previous.base._copy_rows(\n'
                                     '        latest_reviews,\n'
                                     '        "meituan",\n'
