                                                  '    except (TypeError, ValueError):\n'
                                                  '        return None\n'
                                                  '    return None if number != number else number\n'
                                                  '\n'
                                                  '\n'
                                                  'def _item(result: dict[str, Any], number: int) -> dict[str, Any] | '
                                                  'None:\n'
                                                  '    return next(\n'
                                                  '        (\n'
                                                  '            item\n'
                                                  '            for item in result.get("items") or []\n'
                                                  '            if int(item.get("standard_item_id") or 0) == number\n'
                                                  '        ),\n'
                                                  '        None,\n'
                                                  '    )\n'
                                                  '\n'
                                                  '\n'
                                                  'def _latest_performance_row(\n'
