                                                  '            "spend_amount" in row\n'
                                                  '            or "booking_order_amount" in row\n'
                                                  '            or "promotion_performance_30d"\n'
                                                  '            in str(row.get("source_table") or '
                                                  'row.get("__source_table") or "")\n'
                                                  '        )\n'
                                                  '    ]\n'
                                                  '    if not rows:\n'
                                                  '        return {}\n'
                                                  '    return max(\n'
                                                  '        enumerate(rows),\n'
                                                  '        key=lambda pair: (\n'
                                                  '            str(pair[1].get("snapshot_time") or ""),\n'
                                                  '            str(pair[1].get("updated_at") or ""),\n'
                                                  '            str(pair[1].get("created_at") or ""),\n'
                                                  '            str(pair[1].get("business_date") or ""),\n'
                                                  '            pair[0],\n'
                                                  '        ),\n'
                                                  '    )[1]\n'
                                                  '\n'
                                                  '\n'
                                                  'def _score_ratio(\n'
