                                                  '    spend_amount: float | None,\n'
                                                  '    roi: float | None,\n'
                                                  ') -> float:\n'
                                                  '    """Mandatory score after eligibility filtering.\n'
                                                  '\n'
                                                  '    ``promotion_status`` remains as a defensive argument for '
                                                  'compatibility, but\n'
                                                  '    the database and section selectors already restrict records to '
                                                  'RUNNING.\n'
                                                  '    """\n'
                                                  '\n'
                                                  '    if str(promotion_status or "").strip().upper() != "RUNNING":\n'
                                                  '        return 0.0\n'
                                                  '    if spend_amount is None or spend_amount <= 1000:\n'
                                                  '        return 0.0\n'
                                                  '    if roi is None:\n'
