                                              '        return html_text\n'
                                              '\n'
                                              '    switch = _switch_html(active)\n'
                                              '    html_text, count = _PRINT_BUTTON_RE.subn(\n'
                                              '        lambda match: match.group(1) + switch,\n'
                                              '        html_text,\n'
                                              '        count=1,\n'
                                              '    )\n'
                                              '    if count == 0:\n'
                                              '        html_text, count = _TOP_ACTIONS_RE.subn(\n'
