                                              '    return html_text\n'
                                              '\n'
                                              '\n'
                                              'CTRIP_ITEMS: tuple[dict[str, Any], ...] = (\n'
                                              '    {"no": 1, "title": "月度经营趋势 YOY", "weight": "10", "period": "本月累计", '
