                                              'print{{.ctrip-topbar-v52,.ctrip-side-v52{{display:none!important}}.ctrip-page-v52{{display:block;padding:0}}.ctrip-card-v52{{break-inside:avoid;box-shadow:none}}}}\n'
                                              '</style>\n'
