                                      '\n'
                                      'def _e(value: Any) -> str:\n'
                                      '    return html.escape("" if value is None else str(value), quote=True)\n'
                                      '\n'
                                      '\n'
                                      'def _n(value: Any) -> float | None:\n'
                                      '    try:\n'
                                      '        if value in (None, ""):\n'
                                      '            return None\n'
                                      '        number = float(value)\n'
                                      '        return None if number != number else number\n'
                                      '    except (TypeError, ValueError):\n'
                                      '        return None\n'
