                                      '\n'
                                      'def _field(item: dict[str, Any], label: str) -> dict[str, Any]:\n'
                                      '    return next(\n'
                                      '        (field for field in item.get("fields") or [] if field.get("label") == '
                                      'label),\n'
                                      '        {},\n'
                                      '    )\n'
                                      '\n'
                                      '\n'
                                      'def _score_text(item: dict[str, Any]) -> str:\n'
                                      '    score = item.get("item_score")\n'
                                      '    return "待计算" if score is None else f"{float(score):g}分"\n'
                                      '\n'
                                      '\n'
                                      'def _source_box(item: dict[str, Any]) -> str:\n'
                                      '    fields = "、".join(str(value) for value in item.get("source_fields") or []) '
                                      'or "待补充"\n'
                                      '    return (\n'
                                      '        "<div class=\'field-standard-note\'><b>数据库来源：</b>"\n'
                                      '        f"<code>{_e(item.get(\'source_table\') or \'待确认\')}</code><br>"\n'
                                      '        f"<b>对应字段：</b>{_e(fields)}</div>"\n'
                                      '    )\n'
                                      '\n'
                                      '\n'
                                      'def _date_parts(value: Any) -> tuple[str, str]:\n'
                                      '    text = str(value or "")\n'
                                      '    if " 至 " in text:\n'
                                      '        start, end = text.split(" 至 ", 1)\n'
                                      '        return start.strip() or "—", end.strip() or "—"\n'
                                      '    return (text or "—", text or "—")\n'
                                      '\n'
                                      '\n'
                                      'def _daily_points(item: dict[str, Any]) -> list[dict[str, Any]]:\n'
                                      '    points: list[dict[str, Any]] = []\n'
                                      '    for field in item.get("fields") or []:\n'
                                      '        label = str(field.get("label") or "")\n'
                                      '        value = _n(field.get("value"))\n'
                                      '        if not re.fullmatch(r"\\d{4}-\\d{2}-\\d{2}", label) or value is None:\n'
                                      '            continue\n'
                                      '        points.append(\n'
                                      '            {\n'
                                      '                "date": label,\n'
                                      '                "value": value,\n'
                                      '                "note": str(field.get("note") or ""),\n'
                                      '            }\n'
                                      '        )\n'
                                      '    return points[-30:]\n'
                                      '\n'
                                      '\n'
                                      'def _chart_svg(points: list[dict[str, Any]]) -> str:\n'
                                      '    if not points:\n'
                                      '        return "<div class=\'hos-v2-empty\'>当前统计周期没有有效 HOS 评分记录。</div>"\n'
                                      '\n'
                                      '    width, height = 820, 300\n'
                                      '    left, right, top, bottom = 68.0, 790.0, 26.0, 245.0\n'
                                      '    values = [float(point["value"]) for point in points]\n'
                                      '    raw_min, raw_max = min(values), max(values)\n'
                                      '    if raw_min == raw_max:\n'
                                      '        padding = max(abs(raw_min) * 0.08, 0.5)\n'
                                      '        low = max(0.0, raw_min - padding)\n'
                                      '        high = raw_max + padding\n'
                                      '    else:\n'
                                      '        padding = max((raw_max - raw_min) * 0.18, 0.25)\n'
                                      '        low = max(0.0, raw_min - padding)\n'
                                      '        high = raw_max + padding\n'
                                      '    if high <= low:\n'
                                      '        high = low + 1.0\n'
                                      '    span = high - low\n'
                                      '\n'
                                      '    def x_at(index: int) -> float:\n'
                                      '        return left + (right - left) * index / max(1, len(points) - 1)\n'
                                      '\n'
                                      '    def y_at(value: float) -> float:\n'
                                      '        return bottom - (value - low) / span * (bottom - top)\n'
                                      '\n'
                                      '    grid: list[str] = []\n'
                                      '    for index in range(5):\n'
