                                      '.manual-crown-summary-v19{margin-top:16px;padding:14px;border:1px solid '
                                      '#dfe9e5;border-radius:10px;background:#f8fbfa;display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px}\n'
                                      '.manual-crown-summary-v19 '
                                      'small{display:block;color:var(--muted);font-weight:800}.manual-crown-summary-v19 '
                                      'strong{display:block;margin-top:5px;font-size:17px}\n'
                                      '@media(max-width:760px){.manual-crown-form-v19,.manual-crown-summary-v19{grid-template-columns:1fr}}\n'
                                      '</style>\n'
                                      '"""\n'
                                      '\n'
                                      '\n'
                                      '_OLD_CROWN_SCRIPT = re.compile(\n'
                                      '    r"<script>\\s*\\(function\\(\\)\\{.*?crown-save-button.*?</script>",\n'
                                      '    re.DOTALL,\n'
                                      ')\n'
                                      '_CROWN_CARD = re.compile(\n'
                                      '    r"<article class=\'diagnosis-card\'[^>]*id=\'rule-22\'>.*?</article>",\n'
                                      '    re.DOTALL,\n'
                                      ')\n'
                                      '\n'
                                      '\n'
                                      'def _e(value: Any) -> str:\n'
                                      '    return html.escape("" if value is None else str(value), quote=True)\n'
                                      '\n'
                                      '\n'
                                      'def _score_base(result: dict[str, Any]) -> tuple[float, float]:\n'
                                      '    visual = result.get("visual_diagnosis") or {}\n'
                                      '    items = list(visual.get("items") or [])\n'
                                      '    raw = 0.0\n'
                                      '    connected = 0.0\n'
                                      '    for item in items:\n'
                                      '        if int(item.get("standard_item_id") or 0) == 22:\n'
                                      '            continue\n'
                                      '        score = item.get("item_score")\n'
                                      '        if score is None:\n'
                                      '            continue\n'
                                      '        raw += float(score)\n'
                                      '        if item.get("participates_in_score"):\n'
                                      '            connected += float(item.get("base_score") or 0)\n'
                                      '    return round(raw, 4), round(connected, 4)\n'
                                      '\n'
                                      '\n'
                                      'def _manual_crown_card(result: dict[str, Any]) -> str:\n'
                                      '    hotel = str(result.get("hotel_name") or result.get("hotel_id") or "hotel")\n'
                                      '    start = str(result.get("period_start") or "")\n'
                                      '    end = str(result.get("period_end") or "")\n'
                                      '    storage_key = "s14:crown:" + hotel + ":" + start + ":" + end\n'
                                      '    base_raw, base_connected = _score_base(result)\n'
                                      '\n'
                                      '    return f"""\n'
                                      "<article class='diagnosis-card' data-status='manual_pending' data-title='酒店挂冠' "
                                      "id='rule-22'>\n"
                                      "  <div class='card-top'>\n"
                                      "    <div class='rule-no'>23</div>\n"
                                      "    <div class='card-title'><h3>酒店挂冠</h3><p>选择当前挂冠类型，保存后立即计算本项及总得分。</p></div>\n"
                                      "    <div class='card-tags'>\n"
                                      "      <div class='title-meta-item "
                                      "title-period'><small>统计周期</small><strong>人工录入</strong></div>\n"
                                      "      <div class='title-meta-item title-score pending' "
                                      "id='crown-score-box'><small>当前得分</small><div class='title-score-value'><strong "
                                      "id='crown-score'>待计算</strong><span>满分 1分</span></div></div>\n"
                                      "      <span class='status-badge manual' id='crown-status'>待人工录入</span>\n"
                                      '    </div>\n'
                                      '  </div>\n'
                                      "  <div class='result-area'>\n"
                                      "    <div class='viz-card'>\n"
                                      "      <div class='manual-crown-form-v19'>\n"
                                      "        <div class='manual-crown-field-v19'>\n"
                                      "          <label for='crown-type-input'>挂冠类型</label>\n"
                                      "          <select id='crown-type-input'>\n"
                                      "            <option value=''>请选择</option>\n"
                                      "            <option value='黑金挂冠'>黑金挂冠（1分）</option>\n"
                                      "            <option value='普通挂冠'>普通挂冠（0.5分）</option>\n"
                                      "            <option value='无挂冠'>无挂冠（0分）</option>\n"
                                      '          </select>\n'
                                      '        </div>\n'
                                      "        <div class='manual-crown-field-v19'><label "
                                      "for='crown-operator-input'>录入人</label><input id='crown-operator-input' "
                                      "type='text' maxlength='50' placeholder='请输入录入人'></div>\n"
                                      "        <div class='manual-crown-field-v19'><label "
                                      "for='crown-time-input'>录入时间</label><input id='crown-time-input' "
                                      "type='datetime-local'></div>\n"
                                      '      </div>\n'
                                      "      <div class='manual-crown-actions-v19'>\n"
                                      "        <button class='manual-crown-save-v19' type='button' "
                                      "id='crown-save-button'>保存录入</button>\n"
                                      "        <button class='manual-crown-clear-v19' type='button' "
                                      "id='crown-clear-button'>清空</button>\n"
                                      "        <span class='manual-crown-message-v19' "
                                      "id='crown-message'>选择挂冠类型并保存后自动评分。</span>\n"
                                      '      </div>\n'
                                      "      <div class='manual-crown-summary-v19'>\n"
                                      '        <div><small>挂冠类型</small><strong '
                                      "id='crown-type-display'>尚未录入</strong></div>\n"
                                      '        <div><small>本项得分</small><strong '
                                      "id='crown-score-display'>待计算</strong></div>\n"
                                      '        <div><small>录入人</small><strong '
                                      "id='crown-operator-display'>—</strong></div>\n"
                                      '        <div><small>录入时间</small><strong '
                                      "id='crown-time-display'>—</strong></div>\n"
                                      '      </div>\n'
                                      '    </div>\n'
                                      '  </div>\n'
                                      '</article>\n'
                                      '<script>\n'
