                                      '        paid_orders = _sum(records, "paid_orders", "hotel_paid_orders")\n'
                                      '        peer_paid_orders = _sum(records, "peer_paid_orders", '
                                      '"competitor_paid_orders")\n'
                                      '\n'
                                      '        exposure_to_view = _divide(views, exposure)\n'
                                      '        peer_exposure_to_view = _divide(peer_views, peer_exposure)\n'
                                      '        view_to_pay = _divide(paid_orders, views)\n'
                                      '        peer_view_to_pay = _divide(peer_paid_orders, peer_views)\n'
                                      '\n'
                                      '        _set_field(display_item, "曝光人数", exposure, "最近30天每日酒店曝光人数合计")\n'
                                      '        _set_field(display_item, "曝光人数同行均值", peer_exposure, '
                                      '"最近30天每日竞争圈平均曝光人数合计")\n'
                                      '        _set_field(display_item, "浏览人数", views, "最近30天每日酒店浏览人数合计")\n'
                                      '        _set_field(display_item, "浏览人数同行均值", peer_views, "最近30天每日竞争圈平均浏览人数合计")\n'
                                      '        _set_field(display_item, "曝光-浏览转化率", exposure_to_view, '
                                      '"最近30天浏览人数合计÷曝光人数合计")\n'
                                      '        _set_field(display_item, "曝光-浏览转化率同行均值", peer_exposure_to_view, '
                                      '"最近30天竞争圈浏览人数合计÷竞争圈曝光人数合计")\n'
                                      '        _set_field(display_item, "支付订单数", paid_orders, "最近30天每日酒店支付订单数合计")\n'
                                      '        _set_field(display_item, "支付订单数同行均值", peer_paid_orders, '
                                      '"最近30天每日竞争圈平均支付订单数合计")\n'
                                      '        _set_field(display_item, "浏览-支付转化率", view_to_pay, '
                                      '"最近30天支付订单数合计÷浏览人数合计")\n'
                                      '        _set_field(display_item, "浏览-支付转化率同行均值", peer_view_to_pay, '
                                      '"最近30天竞争圈支付订单数合计÷竞争圈浏览人数合计")\n'
                                      '\n'
                                      '    display_item["daily_records"] = []\n'
                                      '    display_item["records"] = []\n'
                                      '    display_item["note"] = (\n'
                                      '        "页面只展示一条近30天汇总记录；曝光、浏览和支付订单按日数据求和，"\n'
                                      '        "一转与二转使用汇总后的分子÷分母重新计算。同行排名仍展示最近业务日期的非空排名。"\n'
                                      '    )\n'
                                      '    return display_item\n'
                                      '\n'
                                      '\n'
                                      'def _flow_summary_card(item: dict[str, Any]) -> str:\n'
                                      '    card = reporting_v23._flow_card(_flow_summary_item(item))\n'
                                      '    return _FIRST_TABLE_CELL_PATTERN.sub(\n'
                                      '        lambda match: match.group(1) + "近30天" + match.group(2),\n'
                                      '        card,\n'
                                      '        count=1,\n'
                                      '    )\n'
                                      '\n'
                                      '\n'
                                      'def _item_four(result: dict[str, Any]) -> dict[str, Any] | None:\n'
                                      '    return next(\n'
                                      '        (\n'
                                      '            item\n'
                                      '            for item in (result.get("visual_diagnosis") or {}).get("items") or '
                                      '[]\n'
                                      '            if int(item.get("standard_item_id") or 0) == 4\n'
                                      '        ),\n'
                                      '        None,\n'
                                      '    )\n'
                                      '\n'
                                      '\n'
                                      'def build_html(result: dict[str, Any]) -> str:\n'
                                      '    html_text = reporting_v28.build_html(result)\n'
                                      '    item = _item_four(result)\n'
                                      '    if item:\n'
                                      '        html_text = _FLOW_CARD_PATTERN.sub(\n'
                                      '            lambda _: _flow_summary_card(item),\n'
                                      '            html_text,\n'
                                      '            count=1,\n'
                                      '        )\n'
                                      '    return html_text.replace("</head>", COMPACT_LAYOUT_STYLE + "</head>", 1)\n'
                                      '\n'
                                      '\n'
                                      'def build_markdown(result: dict[str, Any]) -> str:\n'
                                      '    return reporting_v28.build_markdown(result)\n'
                                      '\n'
                                      '\n'
                                      'def write_reports(result: dict[str, Any], output_dir: str | Path) -> dict[str, '
                                      'str]:\n'
                                      '    paths = reporting_v28.write_reports(result, output_dir)\n'
                                      '    html_path = Path(paths["report_html"])\n'
                                      '    html_path.write_text(build_html(result), encoding="utf-8")\n'
                                      '    return paths\n'
                                      '\n'
