                                     "class='body'>{_table(['活动','开始日期','倒计时','距离km','判断'], _event_rows(events))}<div "
                                     "class='callout'>{_event_suggestion_html(events)}</div></div></section>\n"
                                     "<section class='card' id='modules'><div "
