                                             '    elif low_ratio <= 0.30:\n'
                                             '        ratio, conclusion = 0.6, "低效房型占比为10%–30%，得4.8分。"\n'
                                             '    else:\n'
                                             '        ratio, conclusion = 0.0, "低效房型占比高于30%，得0分。"\n'
                                             '\n'
                                             '    _set_score(item, ratio, "success" if ratio > 0 else "zero")\n'
                                             '    item["note"] = (\n'
                                             '        "严格采用手册阈值：低效房型为近30天出租率低于60%的房型；"\n'
                                             '        "低效房型占比<10%得8分，10%–30%得4.8分，>30%得0分。"\n'
                                             '        + conclusion\n'
                                             '    )\n'
                                             '\n'
                                             '\n'
                                             'def _rate_value(label: str, value: Any) -> float | None:\n'
