                                             '        return 0.6\n'
                                             '    return 0.0\n'
                                             '\n'
                                             '\n'
                                             'def _flow_pair(item: dict[str, Any], label: str, peer_label: str) -> '
                                             'tuple[float, float] | None:\n'
                                             '    actual = _rate_value(label, (_field(item, label) or '
