                                             '        ("浏览人数", "浏览人数同行均值"),\n'
                                             '        ("曝光-浏览转化率", "曝光-浏览转化率同行均值"),\n'
                                             '        ("浏览-支付转化率", "浏览-支付转化率同行均值"),\n'
                                             '    )\n'
                                             '\n'
                                             '    sub_scores: list[float] = []\n'
                                             '    details: list[str] = []\n'
                                             '    for label, peer_label in definitions:\n'
                                             '        pair = _flow_pair(item, label, peer_label)\n'
                                             '        if pair is None and label == "浏览-支付转化率":\n'
                                             '            # Some source versions expose the same second-conversion '
                                             'metric as\n'
                                             '            # “支付转化率”. Use it only as an explicit field alias.\n'
                                             '            pair = _flow_pair(item, "支付转化率", "支付转化率同行均值")\n'
                                             '        if pair is None:\n'
                                             '            _set_score(item, None, "missing")\n'
