                                             '            return\n'
                                             '        actual, peer = pair\n'
                                             '        comparison = actual / peer\n'
                                             '        score = _ratio_score(comparison)\n'
                                             '        sub_scores.append(score)\n'
                                             '        '
                                             'details.append(f"{label}÷同行均值={comparison:.2f}，子项比例{score:.0%}")\n'
                                             '\n'
                                             '    overall_ratio = sum(sub_scores) / 4\n'
                                             '    _set_score(item, overall_ratio, "success" if overall_ratio > 0 else '
