                                             '        + "；".join(details)\n'
                                             '    )\n'
                                             '\n'
                                             '\n'
                                             'def _detected_location_term(suffix: str) -> str | None:\n'
                                             '    return next((term for term in _LOCATION_TERMS if term in suffix), '
                                             'None)\n'
                                             '\n'
                                             '\n'
                                             'def _patch_page_entry_score(result: dict[str, Any]) -> None:\n'
                                             '    item = _item(result, 10)\n'
                                             '    if not item:\n'
                                             '        return\n'
                                             '\n'
                                             '    name = str((_field(item, "酒店展示名称") or {}).get("value") or '
