                                             '        return\n'
                                             '\n'
                                             '    if not suffix:\n'
                                             '        _set_score(item, 0.0, "zero")\n'
                                             '        item["note"] = "酒店展示名称未添加后缀，按手册得0分。"\n'
                                             '        return\n'
                                             '\n'
                                             '    matched = existing_hotword or _detected_location_term(suffix)\n'
                                             '    if matched:\n'
                                             '        if hotword_field is not None:\n'
