                                             'FLOW_SOURCE_TABLE),\n'
                                             '        _rank_field("曝光人数同行排名", exposure_rank, exposure_rank_date),\n'
                                             '        _field("浏览人数", views, "直接读取 browse_uv", FLOW_SOURCE_TABLE),\n'
