                                            'def _patch_daily_exposure_ratios(\n'
                                            '    result: dict[str, Any],\n'
                                            '    sections: dict[str, list[dict[str, Any]]],\n'
                                            ') -> dict[str, Any]:\n'
                                            '    """Use the database percentage for each exposure day when it is '
                                            'available.\n'
                                            '\n'
                                            '    ``ad_exposure_ratio_pct`` may be stored either as ``8.95`` or '
                                            '``0.0895``.\n'
                                            '    ``_pct_value`` normalizes both forms to the decimal value used by '
                                            'the\n'
                                            '    report renderer. The original formula remains the fallback when the\n'
                                            '    database percentage is missing or invalid.\n'
                                            '    """\n'
                                            '    exposure_rows = _latest_distinct_days(sections.get("exposure_daily") '
                                            'or [])\n'
                                            '    rows_by_date = {\n'
                                            '        str(row.get("business_date") or "")[:10]: row\n'
                                            '        for row in exposure_rows\n'
                                            '        if str(row.get("business_date") or "")[:10]\n'
                                            '    }\n'
                                            '\n'
                                            '    exposure_item = next(\n'
                                            '        (\n'
                                            '            item\n'
                                            '            for item in result.get("items") or []\n'
                                            '            if int(item.get("standard_item_id") or 0) == 3\n'
                                            '        ),\n'
                                            '        None,\n'
                                            '    )\n'
                                            '    if not exposure_item:\n'
                                            '        return result\n'
                                            '\n'
                                            '    for field in exposure_item.get("fields") or []:\n'
                                            '        label = str(field.get("label") or "")\n'
                                            '        if not label.endswith(" 广告曝光占比"):\n'
                                            '            continue\n'
                                            '\n'
                                            '        business_date = label[:10]\n'
                                            '        row = rows_by_date.get(business_date)\n'
                                            '        if not row:\n'
                                            '            continue\n'
                                            '\n'
                                            '        database_ratio = _pct_value(row.get("ad_exposure_ratio_pct"))\n'
                                            '        if database_ratio is None:\n'
                                            '            field["note"] = "ad_exposure_ratio_pct 缺失，回退使用 ad_exposure ÷ '
                                            'total_exposure"\n'
                                            '            continue\n'
                                            '\n'
                                            '        field["value"] = database_ratio\n'
                                            '        field["note"] = "ad_exposure_ratio_pct（数据库原值，已统一换算为小数）"\n'
                                            '        field["origin"] = "数据库原值"\n'
                                            '\n'
                                            '    exposure_item["note"] = (\n'
                                            '        "近30天总占比按广告曝光合计 ÷ 整体曝光合计计算；"\n'
                                            '        "每日占比优先使用数据库 ad_exposure_ratio_pct，缺失时回退公式。"\n'
                                            '    )\n'
                                            '    result["rule_version"] = "2026-07-14"\n'
                                            '    return result\n'
                                            '\n'
                                            '\n'
                                            'def build_visual_diagnosis(\n'
