                                            '    )\n'
                                            '\n'
                                            '\n'
                                            'def _patch_scan_orders(\n'
                                            '    result: dict[str, Any],\n'
                                            '    sections: dict[str, list[dict[str, Any]]],\n'
                                            ') -> None:\n'
                                            '    scan_item = _item(result, 7)\n'
                                            '    if not scan_item:\n'
                                            '        return\n'
                                            '\n'
                                            '    scan_item["source_table"] = '
