                                            'row.get("__source_table") or "").strip().lower()\n'
                                            '    return platform in _MEITUAN_ALIASES or '
                                            'source_table.endswith("meituan_ota_goods_price_mapping")\n'
                                            '\n'
                                            '\n'
                                            'def _latest_meituan_products(sections: dict[str, list[dict[str, Any]]]) '
                                            '-> list[dict[str, Any]]:\n'
