                                            '        return None\n'
                                            '    if value > 4.9:\n'
                                            '        return 1.0\n'
                                            '    if value >= 4.7:\n'
                                            '        return 0.8\n'
                                            '    return 0.0\n'
                                            '\n'
                                            '\n'
                                            'def _patch_review_score(result: dict[str, Any]) -> None:\n'
                                            '    item = _item(result, 13)\n'
                                            '    if not item:\n'
                                            '        return\n'
                                            '\n'
                                            '    meituan_score = _n(_field_value(item, "美团评分"))\n'
                                            '    dianping_score = _n(_field_value(item, "大众点评评分"))\n'
                                            '\n'
                                            '    # The handbook explicitly treats Dianping as a sub-field but does not '
                                            'define\n'
                                            '    # any averaging/weighting rule. Use the Meituan score as the primary '
                                            'scoring\n'
                                            '    # value and only fall back to Dianping when Meituan is absent. This '
                                            'avoids\n'
                                            '    # inventing an undocumented cross-platform aggregation formula.\n'
                                            '    if meituan_score is not None:\n'
                                            '        scoring_score = meituan_score\n'
                                            '        scoring_source = "美团评分"\n'
                                            '    elif dianping_score is not None:\n'
                                            '        scoring_score = dianping_score\n'
                                            '        scoring_source = "大众点评评分（美团评分缺失时备用）"\n'
                                            '    else:\n'
                                            '        scoring_score = None\n'
                                            '        scoring_source = "无可用点评分"\n'
                                            '\n'
                                            '    ratio = _review_score_ratio(scoring_score)\n'
                                            '    item["score_ratio"] = ratio\n'
                                            '    item["item_score"] = (\n'
                                            '        round(float(item.get("base_score") or 10) * ratio, 2)\n'
                                            '        if ratio is not None\n'
                                            '        else None\n'
                                            '    )\n'
                                            '    item["data_status"] = "success" if ratio is not None else "missing"\n'
                                            '    item["note"] = (\n'
                                            '        f"本项按{scoring_source}计分；大众点评评分作为口碑分析子字段展示。"\n'
                                            '        "严格采用手册阈值：点评分>4.9得10分；4.7≤点评分≤4.9得8分；"\n'
                                            '        "点评分<4.7得0分。未定义两平台平均或加权规则，因此不自行合并。"\n'
                                            '    )\n'
                                            '\n'
                                            '\n'
                                            'def build_visual_diagnosis(\n'
