                                            '\n'
                                            '\n'
                                            'def _patch_scan_order_score(result: dict[str, Any]) -> None:\n'
                                            '    item = _item(result, 7)\n'
                                            '    if not item:\n'
                                            '        return\n'
                                            '\n'
                                            '    count_field = _field(item, "月扫码订单")\n'
                                            '    count = _n(count_field.get("value") if count_field else None)\n'
