                                            '        "1–59、61–120及恰好120单的评分未定义。" + conclusion\n'
                                            '    )\n'
                                            '\n'
                                            '\n'
                                            'def _room_has_selling_point(name: str) -> bool:\n'
                                            '    return any(term in name for term in _ROOM_SELLING_POINT_TERMS)\n'
                                            '\n'
                                            '\n'
                                            'def _patch_room_name_score(result: dict[str, Any]) -> None:\n'
                                            '    item = _item(result, 11)\n'
                                            '    if not item:\n'
                                            '        return\n'
                                            '\n'
                                            '    fields = list(item.get("fields") or [])\n'
                                            '    if not fields:\n'
