                                            '        )\n'
                                            '        field["origin"] = "名称长度与卖点词检查"\n'
                                            '\n'
                                            '    if any(length < 5 for _, length, _ in checks):\n'
                                            '        _set_score(item, 0.0, "zero")\n'
                                            '        conclusion = "存在少于5个字的房型名称，得0分。"\n'
                                            '    elif any(length == 5 for _, length, _ in checks):\n'
                                            '        _set_score(item, None, "pending_rule")\n'
                                            '        conclusion = "存在恰好5个字的房型名称，手册未定义该边界。"\n'
