                                            '        return\n'
                                            '\n'
                                            '    count = _n((_field(item, "已报名权益数量") or {}).get("value"))\n'
                                            '    if count is None:\n'
                                            '        _set_score(item, None, "missing")\n'
                                            '        return\n'
                                            '\n'
                                            "    # Apply the handbook's three-tier total-table rule. It is the only "
                                            'complete\n'
                                            '    # rule that defines the 3–5 range.\n'
                                            '    if count > 5:\n'
                                            '        _set_score(item, 1.0, "success")\n'
                                            '        conclusion = "已报名权益大于5项，得4分。"\n'
                                            '    elif count >= 3:\n'
                                            '        _set_score(item, 0.6, "success")\n'
                                            '        conclusion = "已报名权益为3–5项，得2.4分。"\n'
                                            '    else:\n'
                                            '        _set_score(item, 0.0, "zero")\n'
                                            '        conclusion = "已报名权益少于3项，得0分。"\n'
                                            '\n'
                                            '    item["note"] = (\n'
                                            '        "采用规则手册总表三档：已报名权益>5项得4分；3–5项得2.4分；"\n'
                                            '        "<3项得0分。" + conclusion\n'
                                            '    )\n'
                                            '\n'
                                            '\n'
                                            'def _recalculate_totals(result: dict[str, Any]) -> None:\n'
                                            '    items = list(result.get("items") or [])\n'
