                                            '    )\n'
                                            '    result["raw_score"] = raw_score\n'
                                            '    result["connected_base_score"] = connected_base\n'
                                            '    result["normalized_score"] = (\n'
                                            '        round(raw_score / connected_base * 100, 2)\n'
                                            '        if connected_base\n'
                                            '        else None\n'
                                            '    )\n'
                                            '\n'
                                            '\n'
                                            'def build_visual_diagnosis(\n'
                                            '    sections: dict[str, list[dict[str, Any]]],\n'
